const addDocBtn = document.getElementById('add-doc-btn');
const docTitle  = document.getElementById('doc-title');
const docText   = document.getElementById('doc-text');

let history  = [];
let streaming = false;
let toolPills = {}; // name -> pill element (for updating with result)

// ── Document management ─────────────────────────────────────────────

async function addDocument() {
  const title = docTitle.value.trim();
  const text  = docText.value.trim();
  if (!text) return;

  addDocBtn.disabled = true;
  addDocBtn.textContent = 'Adding…';

  const res = await fetch('/documents', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ title, text }),
  });
  const data = await res.json();

  docTitle.value = '';
  docText.value  = '';
  addDocBtn.disabled = false;
  addDocBtn.textContent = '+ Add Document';

  appendDocItem(title || `Document ${data.total}`, text);
}

function appendDocItem(title, text) {
  docEmpty?.remove();
  const item = document.createElement('div');
  item.className = 'doc-item';
  item.innerHTML = `<strong>${escHtml(title)}</strong>${escHtml(text.slice(0, 80))}${text.length > 80 ? '…' : ''}`;
  docList.appendChild(item);
}

addDocBtn.addEventListener('click', addDocument);

// ── Chat ────────────────────────────────────────────────────────────

function escHtml(s) {
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

function removeEmptyState() {
  document.getElementById('empty-state')?.remove();
}

function appendMessage(role, text = '') {
  removeEmptyState();
  const msg  = document.createElement('div');
  msg.className = `message ${role}`;

  const avatar = document.createElement('div');
  avatar.className = 'avatar';
  avatar.textContent = role === 'user' ? '🧑' : '🤖';

  const body = document.createElement('div');
  body.className = 'msg-body';

  const bubble = document.createElement('div');
  bubble.className = 'bubble';
  bubble.textContent = text;

  body.appendChild(bubble);
  msg.appendChild(avatar);
  msg.appendChild(body);
  chatEl.appendChild(msg);
  chatEl.scrollTop = chatEl.scrollHeight;
  return { msg, body, bubble };
}

function appendToolPill(body, name, args) {
  const pill = document.createElement('details');
  pill.className = 'tool-pill';
  pill.open = true;

  const argsStr = Object.keys(args).length
    ? JSON.stringify(args, null, 2)
    : '(no arguments)';

  pill.innerHTML = `
    <summary>
      <span class="tool-icon">🔧</span>
      <span class="tool-name">${escHtml(name)}</span>
      <span class="tool-status pending" id="status-${escHtml(name)}">running…</span>
    </summary>
    <div class="tool-body">
      <div class="tool-section-label">Args</div>
      <div class="tool-code">${escHtml(argsStr)}</div>
      <div class="tool-section-label">Result</div>
      <div class="tool-code" id="result-${escHtml(name)}">…</div>
    </div>`;

  body.appendChild(pill);
  chatEl.scrollTop = chatEl.scrollHeight;
  return pill;
}

function updateToolPill(name, result) {
  const statusEl = document.getElementById(`status-${name}`);
  const resultEl = document.getElementById(`result-${name}`);
  if (statusEl) { statusEl.textContent = 'done'; statusEl.className = 'tool-status done'; }
  if (resultEl) resultEl.textContent = result.slice(0, 400) + (result.length > 400 ? '…' : '');
}

async function send() {
  const text = inputEl.value.trim();
  if (!text || streaming) return;

  streaming = true;
  sendBtn.disabled = true;
  inputEl.value = '';
  inputEl.style.height = 'auto';
  toolPills = {};

