function appendToolPill(body, name, args) {
  const argsStr = Object.keys(args).length ? JSON.stringify(args, null, 2) : '(no arguments)';

  const statusEl = document.createElement('span');
  statusEl.className = 'tool-status pending';
  statusEl.textContent = 'running…';

  const resultEl = document.createElement('div');
  resultEl.className = 'tool-code';
  resultEl.textContent = '…';

  const summary = document.createElement('summary');
  summary.innerHTML = `<span class="tool-icon">🔧</span><span class="tool-name">${escHtml(name)}</span>`;
  summary.appendChild(statusEl);

  const argsEl = document.createElement('div');
  argsEl.className = 'tool-code';
  argsEl.textContent = argsStr;

  const bodyDiv = document.createElement('div');
  bodyDiv.className = 'tool-body';
  bodyDiv.innerHTML = '<div class="tool-section-label">Args</div>';
  bodyDiv.appendChild(argsEl);
  bodyDiv.innerHTML += '<div class="tool-section-label">Result</div>';
  bodyDiv.appendChild(resultEl);

  const pill = document.createElement('details');
  pill.className = 'tool-pill';
  pill.open = true;
  pill.appendChild(summary);
  pill.appendChild(bodyDiv);

  body.appendChild(pill);
  chatEl.scrollTop = chatEl.scrollHeight;

  // Queue element refs so updateToolPill finds the right pill when same tool fires multiple times
  if (!toolCallQueue[name]) toolCallQueue[name] = [];
  toolCallQueue[name].push({ statusEl, resultEl });
}

function updateToolPill(name, result) {
  const entry = toolCallQueue[name]?.shift();
  if (!entry) return;
  entry.statusEl.textContent = 'done';
  entry.statusEl.className = 'tool-status done';
  entry.resultEl.textContent = result.length > 400 ? result.slice(0, 400) + '…' : result;
}

