import json
import math
from datetime import datetime

import ollama
from fastapi import FastAPI
from fastapi.responses import FileResponse, StreamingResponse
from fastapi.staticfiles import StaticFiles
from pydantic import BaseModel

app = FastAPI()
MODEL = "qwen3.5:9b"

SYSTEM_PROMPT = """You are a helpful AI assistant with access to tools and a knowledge base.
If you recieve the required response from the tool you call do not call it again.

- Use `get_current_time` when asked about time or today's date.
- Use `calculator` for any math — never compute in your head.
- Use `search_knowledge_base` before answering questions about topics that may be in uploaded documents. Always search first if the user references docs or a topic you were given.
Be concise and accurate."""

# ── Tools ──────────────────────────────────────────────────────────────────

TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "get_current_time",
            "description": "Returns the current date and time.",
            "parameters": {"type": "object", "properties": {}, "required": []},
        },
    },
    {
        "type": "function",
        "function": {
            "name": "calculator",
            "description": "Evaluates a mathematical expression. Supports standard operators and math functions like sqrt, log, sin, cos.",
            "parameters": {
                "type": "object",
                "properties": {
                    "expression": {
                        "type": "string",
                        "description": "Math expression e.g. '2 ** 10', 'sqrt(144)', '(3 + 4) * 2'",
                    }
                },
                "required": ["expression"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "search_knowledge_base",
            "description": "Searches uploaded documents for relevant information. Call this before answering questions about specific topics.",
            "parameters": {
                "type": "object",
                "properties": {
                    "query": {
                        "type": "string",
                        "description": "Natural language search query",
                    }
                },
                "required": ["query"],
            },
        },
    },
]


# ── In-memory vector store (cosine similarity, no extra deps) ───────────────

def _cosine(a: list[float], b: list[float]) -> float:
    dot = sum(x * y for x, y in zip(a, b))
    na = math.sqrt(sum(x * x for x in a))
    nb = math.sqrt(sum(x * x for x in b))
    return dot / (na * nb) if na and nb else 0.0


class VectorStore:
    def __init__(self):
        self.docs: list[str] = []
        self.embeddings: list[list[float]] = []

    def add(self, text: str) -> int:
        emb = ollama.embed(model=MODEL, input=text).embeddings[0]
        self.docs.append(text)
        self.embeddings.append(emb)
        return len(self.docs)

    def search(self, query: str, k: int = 3) -> list[str]:
        if not self.docs:
            return []
        q_emb = ollama.embed(model=MODEL, input=query).embeddings[0]
        scored = sorted(
            range(len(self.docs)),
            key=lambda i: _cosine(q_emb, self.embeddings[i]),
            reverse=True,
        )
        return [self.docs[i] for i in scored[:k]]


store = VectorStore()


# ── Tool execution ──────────────────────────────────────────────────────────

def _safe_eval(expr: str) -> str:
    ns = {k: getattr(math, k) for k in dir(math) if not k.startswith("_")}
    ns.update({"abs": abs, "round": round, "pow": pow})
    try:
        return str(eval(compile(expr, "<expr>", "eval"), {"__builtins__": {}}, ns))
    except Exception as e:
        return f"Error: {e}"


def execute_tool(name: str, args: dict) -> str:
    if name == "get_current_time":
        return datetime.now().strftime("%A, %B %d, %Y at %I:%M %p")
    if name == "calculator":
        return _safe_eval(args.get("expression", ""))
    if name == "search_knowledge_base":
        results = store.search(args.get("query", ""))
        return "\n\n---\n\n".join(results) if results else "No relevant documents found."
    return f"Unknown tool: {name}"


# ── API ─────────────────────────────────────────────────────────────────────

class ChatRequest(BaseModel):
    message: str
    history: list[dict] = []
    thinking: bool = True


class DocumentRequest(BaseModel):
    title: str = ""
    text: str


@app.get("/")
def root():
    return FileResponse("static/index.html")


@app.get("/models")
def list_models():
    return {"models": [m.model for m in ollama.list().models]}

@app.get("/models/selected")
def show_selected_model():
    return {"selected_model": MODEL}

@app.post("/documents")
def add_document(req: DocumentRequest):
    text = f"{req.title}\n\n{req.text}".strip() if req.title else req.text
    total = store.add(text)
    return {"status": "ok", "total": total}


@app.get("/documents")
def get_documents():
    return {
        "count": len(store.docs),
        "documents": [{"index": i, "preview": d[:120]} for i, d in enumerate(store.docs)],
    }


@app.post("/chat/stream")
def chat_stream(req: ChatRequest):
    messages = (
        [{"role": "system", "content": SYSTEM_PROMPT}]
        + req.history
        + [{"role": "user", "content": req.message}]
    )

    def generate():
        current = list(messages)

        # Agentic loop — keep calling until no tool calls remain
        while True:
            response = ollama.chat(model=MODEL, messages=current, tools=TOOLS, think=req.thinking)
            tool_calls = response.message.tool_calls

            if not tool_calls:
                # Final answer: emit content as a single token event
                content = response.message.content or ""
                yield f"data: {json.dumps({'type': 'token', 'content': content})}\n\n"
                break

            current.append(response.message)

            for tc in tool_calls:
                name = tc.function.name
                args = tc.function.arguments if isinstance(tc.function.arguments, dict) else {}

                yield f"data: {json.dumps({'type': 'tool_call', 'name': name, 'args': args})}\n\n"

                result = execute_tool(name, args)

                yield f"data: {json.dumps({'type': 'tool_result', 'name': name, 'result': result})}\n\n"

                current.append({"role": "tool", "content": result, "name": name})

        yield "data: [DONE]\n\n"

    return StreamingResponse(generate(), media_type="text/event-stream")


app.mount("/static", StaticFiles(directory="static"), name="static")

